def is_fairy_tale(title: str) -> bool:
    fairy_tale_keywords = {
        'princess', 'knight', 'fairy', 'magic', 'once upon a time',
        'dragon', 'goblin', 'elf', 'giant', 'dwarf', 'spell'
    }
    title_lower = title.lower()
    return any(keyword in title_lower for keyword in fairy_tale_keywords)

# Example usage:
print(is_fairy_tale("The Three Little Pigs"))  # Output: True
print(is_fairy_tale("Harry Potter"))          # Output: True
print(is_fairy_tale("The Great Gatsby"))      # Output: False
